mapper.select:
SELECT submit_id, pass, exe_message, case_judge_res, use_time, use_memory FROM tb_user_submit
AND question_id = #{questionId}
AND exam_id = #{examId}
AND exam_id is null
AND user_id = #{userId}
AND (create_time >= #{currentTime} or update_time >= #{currentTime})
ORDER BY COALESCE(update_time, create_time) DESC, submit_id DESC LIMIT 1

SELECT DATE_FORMAT(create_time, '%Y-%m-%d') AS study_date, COUNT(1) AS submission_count FROM tb_user_submit WHERE user_id = #{userId}
AND create_time >= #{sinceTime}
GROUP BY DATE_FORMAT(create_time, '%Y-%m-%d') ORDER BY study_date DESC

SELECT submit_id, user_id, question_id, exam_id, program_type, user_code, pass, score, exe_message, case_judge_res, use_time, use_memory, create_by, create_time, update_by, update_time FROM tb_user_submit WHERE user_id = #{userId} AND exam_id = #{examId}
AND (create_time >= #{sinceTime} OR update_time >= #{sinceTime})
ORDER BY COALESCE(update_time, create_time) DESC, submit_id DESC LIMIT 1

SELECT submit_id, user_id, question_id, exam_id, program_type, user_code, pass, score, exe_message, case_judge_res, use_time, use_memory, create_by, create_time, update_by, update_time FROM tb_user_submit WHERE user_id = #{userId}
AND question_id = #{questionId}
AND exam_id = #{examId}
AND exam_id IS NULL
ORDER BY COALESCE(update_time, create_time) DESC, submit_id DESC LIMIT #{limit}
